from datetime import datetime


def get_greeting_period(hour: int) -> str:
    if hour < 12:
        return "早上好"
    if hour < 18:
        return "下午好"
    return "晚上好"


def main() -> None:
    now = datetime.now()
    period = get_greeting_period(now.hour)
    print("Hello, World!")
    print(f"现在时间是 {now.strftime('%Y-%m-%d %H:%M:%S')}，{period}！")
    print("欢迎开始学习 Python。")


if __name__ == "__main__":
    main()

