from datetime import datetime


def get_greeting_by_time():
    hour = datetime.now().hour
    if hour < 12:
        return "早上好"
    if hour < 18:
        return "下午好"
    return "晚上好"


def ask_non_empty_name():
    while True:
        name = input("请输入你的名字：").strip()
        if name:
            return name
        print("名字不能为空，请重新输入。")


def main():
    print("欢迎来到问候程序！输入名字后可以获得更贴心的问候。")

    while True:
        name = ask_non_empty_name()
        greeting = get_greeting_by_time()
        print(f"{greeting}，{name}！欢迎学习 Python。")

        choice = input("是否继续问候下一位？(y/n)：").strip().lower()
        if choice != "y":
            print("感谢使用，再见！")
            break


if __name__ == "__main__":
    main()

def read_number(prompt):
    while True:
        try:
            return float(input(prompt))
        except ValueError:
            print("输入有误，请输入有效数字。")


def choose_operation():
    operations = {
        "+": ("加法", lambda a, b: a + b),
        "-": ("减法", lambda a, b: a - b),
        "*": ("乘法", lambda a, b: a * b),
        "/": ("除法", lambda a, b: a / b if b != 0 else None),
    }

    while True:
        op = input("请选择运算符（+ - * /）：").strip()
        if op in operations:
            return op, operations[op]
        print("不支持的运算符，请重新输入。")


def main():
    print("欢迎使用简易计算器！")

    while True:
        a = read_number("请输入第一个数字：")
        b = read_number("请输入第二个数字：")
        op, (op_name, func) = choose_operation()

        result = func(a, b)
        if result is None:
            print("除数不能为 0，请重新尝试。")
        else:
            print(f"本次进行的是{op_name}，结果是：{result}")

        again = input("是否继续计算？(y/n)：").strip().lower()
        if again != "y":
            print("感谢使用简易计算器，再见！")
            break


if __name__ == "__main__":
    main()

def read_int(prompt, allow_zero=False):
    while True:
        try:
            value = int(input(prompt))
            if not allow_zero and value == 0:
                print("该值不能为 0，请重新输入。")
                continue
            return value
        except ValueError:
            print("输入有误，请输入整数。")


def main():
    print("欢迎使用范围数字打印程序！")
    start = read_int("请输入起始数字：", allow_zero=True)
    end = read_int("请输入结束数字：", allow_zero=True)
    step = read_int("请输入步长（不能为 0）：")

    if start < end and step < 0:
        step = abs(step)
    elif start > end and step > 0:
        step = -step

    stop = end + 1 if step > 0 else end - 1
    numbers = list(range(start, stop, step))

    if not numbers:
        print("根据当前起止范围和步长，没有可输出的数字。")
        return

    print("输出结果如下：")
    for index, number in enumerate(numbers, start=1):
        print(f"第 {index} 个数字：{number}")

    print(f"共输出 {len(numbers)} 个数字。")
    print(f"最小值：{min(numbers)}，最大值：{max(numbers)}")


if __name__ == "__main__":
    main()

# 读取用户输入的数字，并在输入错误时反复提示。
def read_number(prompt):
    while True:
        try:
            # 使用 float() 支持整数和小数输入。
            return float(input(prompt))
        except ValueError:
            # 如果转换失败，说明输入不是有效数字。
            print("输入有误，请输入有效数字。")


# 让用户选择要执行的运算类型，并返回运算信息。
def choose_operation():
    # 使用字典保存“运算符 -> 运算名称与计算方法”的对应关系。
    operations = {
        "+": ("加法", lambda a, b: a + b),
        "-": ("减法", lambda a, b: a - b),
        "*": ("乘法", lambda a, b: a * b),
        "/": ("除法", lambda a, b: a / b if b != 0 else None),
    }

    while True:
        # 读取用户输入的运算符。
        op = input("请选择运算符（+ - * /）：").strip()

        # 如果输入合法，就返回该运算符和对应的计算规则。
        if op in operations:
            return op, operations[op]

        # 如果输入不合法，则提示重新输入。
        print("不支持的运算符，请重新输入。")


# 程序主入口，负责组织完整的计算流程。
def main():
    print("欢迎使用简易计算器！")

    # 循环执行，让用户可以连续进行多次计算。
    while True:
        # 读取两个参与运算的数字。
        a = read_number("请输入第一个数字：")
        b = read_number("请输入第二个数字：")

        # 获取运算符、运算名称和具体函数。
        op, (op_name, func) = choose_operation()

        # 调用选中的函数完成计算。
        result = func(a, b)

        # 对除以 0 的情况进行单独处理。
        if result is None:
            print("除数不能为 0，请重新尝试。")
        else:
            # 正常输出计算结果。
            print(f"本次进行的是{op_name}，结果是：{result}")

        # 询问用户是否继续下一轮计算。
        again = input("是否继续计算？(y/n)：").strip().lower()
        if again != "y":
            print("感谢使用简易计算器，再见！")
            break


# 只有在直接运行本文件时，才执行主函数。
if __name__ == "__main__":
    main()
